import React from 'react';

function TableTemplate({ data, columns, entityIdKey, onEdit, onDelete }) {
  if (!data || data.length === 0) {
    return (
      <div className="table-card">
        <h3 className="table-header">📊 All Records</h3>
        <div className="table-empty">
          <div className="table-empty-icon">📭</div>
          <div>No records found.</div>
          <div className="table-empty-sub">
            Add some records to see them here!
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="table-card">
      <h3 className="table-header">📊 All Records ({data.length})</h3>

      <table className="table">
        <thead>
          <tr>
            {columns.map((col) => (
              <th key={col.key}>{col.header}</th>
            ))}
            <th>Actions</th>
          </tr>
        </thead>

        <tbody>
          {data.map((item, index) => (
            <tr key={item[entityIdKey]}>
              {columns.map((col) => (
                <td key={col.key}>
                  {item[col.key] === null || item[col.key] === undefined ? (
                    <span className="table-na">N/A</span>
                  ) : (
                    item[col.key]
                  )}
                </td>
              ))}
              <td className="table-actions">
                <button
                  className="btn btn-primary btn-sm"
                  onClick={() => onEdit(item)}
                >
                  ✏️ Edit
                </button>
                <button
                  className="btn btn-danger btn-sm"
                  onClick={() => onDelete(item[entityIdKey])}
                >
                  🗑️ Delete
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default TableTemplate;
